#[test]
fn controller_prompts_patch_agent_after_clean_review_and_reopens_after_typing() {
    let root = git_repo("workspace-review-done-confirmation");
    fs::write(root.join("README.md"), "before\n").unwrap();
    git(&root, ["add", "README.md"]);
    git(&root, ["commit", "-m", "ADD initial readme fixture"]);
    let backend = FakeBackend::new([
        "implemented patch\n@work-leaf patch update readme\n--- a/README.md\n+++ b/README.md\n@@ -1 +1 @@\n-before\n+after\n@work-leaf end\n@work-leaf done",
        "summary: README changes from before to after",
        "NO_FINDINGS",
        "follow-up after reopen",
    ]);
    let chat = CommandChat::new(root, backend.clone()).with_max_review_rounds(4);
    let mut controller = WorkLeafController::new(chat);

    let agent_id = controller.create_agent("update readme").unwrap();

    assert!(controller.wait_for_idle(Duration::from_secs(2)));
    let snapshot = controller.snapshot();
    let patch_agent = snapshot.session(&agent_id).expect("patch agent exists");
    assert!(
        patch_agent
            .lines
            .iter()
            .any(|line| line == "work-leaf: Is this feature done? yes/no"),
        "{:?}",
        patch_agent.lines
    );

    let sends_after_review = backend.sends().len();
    controller.send_message(&agent_id, "yes").unwrap();
    assert_eq!(
        backend.sends().len(),
        sends_after_review,
        "answering the work-leaf yes/no prompt must not send `yes` to the agent"
    );
    let snapshot = controller.snapshot();
    let patch_agent = snapshot.session(&agent_id).expect("patch agent exists");
    assert!(patch_agent.lines.iter().any(|line| line == "user: yes"));
    assert!(
        patch_agent
            .lines
            .iter()
            .any(|line| line == "work-leaf: feature marked done")
    );

    controller
        .send_message(&agent_id, "actually continue")
        .unwrap();
    assert!(controller.wait_for_idle(Duration::from_secs(2)));
    let snapshot = controller.snapshot();
    let patch_agent = snapshot.session(&agent_id).expect("patch agent exists");
    assert!(
        patch_agent
            .lines
            .iter()
            .any(|line| line == "work-leaf: feature reopened")
    );
    assert!(
        patch_agent
            .lines
            .iter()
            .any(|line| line == "follow-up after reopen")
    );
    assert!(
        backend
            .sends()
            .iter()
            .any(|(target, prompt)| { target == &agent_id && prompt == "actually continue" })
    );
}

